public void ReportSalesWayBill()
{   
    SalesParameters    salesParameters = SalesParameters::find();

    if(!salesParameters.KPMGCommon_ERFormatWaybillId)
    {
        warning("@KPMGCommon:ERFormatWayBillNoExist");
    }
    else
    {
        ERModelDefinitionInputParametersAction  obj = new ERModelDefinitionInputParametersAction();
        obj.addParameter('model/$PackingSlipId', custPackingSlipJour.PackingSlipId);
        obj.addParameter('model/$DeliveryDate', custPackingSlipJour.DeliveryDate);
        ERObjectsFactory::createFormatMappingRunByFormatMappingId(salesParameters.KPMGCommon_ERFormatWaybillId,"").withParameter(obj).run();
    }
}
